import{_ as o,o as a,c as l,ag as i}from"./chunks/framework.DEqXEGcv.js";const p=JSON.parse('{"title":"Docker 应用商店","description":"","frontmatter":{},"headers":[],"relativePath":"zh/docs/guide/docker.md","filePath":"zh/docs/guide/docker.md"}'),r={name:"zh/docs/guide/docker.md"};function t(c,e,d,s,n,h){return a(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="docker-应用商店" tabindex="-1">Docker 应用商店 <a class="header-anchor" href="#docker-应用商店" aria-label="Permalink to &quot;Docker 应用商店&quot;">​</a></h1><p>RDE 提供可视化的 Docker 容器管理和应用商店，无需记忆复杂命令即可部署和管理容器应用。</p><h2 id="应用商店" tabindex="-1">应用商店 <a class="header-anchor" href="#应用商店" aria-label="Permalink to &quot;应用商店&quot;">​</a></h2><p>预置常用应用模板，一键部署：</p><ul><li>数据库：MySQL, PostgreSQL, Redis, MongoDB</li><li>Web 服务：Nginx, Caddy, Apache</li><li>开发工具：GitLab, Jenkins, Portainer</li><li>更多社区应用持续更新</li></ul><h2 id="容器管理" tabindex="-1">容器管理 <a class="header-anchor" href="#容器管理" aria-label="Permalink to &quot;容器管理&quot;">​</a></h2><h3 id="容器操作" tabindex="-1">容器操作 <a class="header-anchor" href="#容器操作" aria-label="Permalink to &quot;容器操作&quot;">​</a></h3><ul><li><strong>创建</strong>：通过应用模板或自定义配置创建容器</li><li><strong>启动/停止</strong>：一键控制容器运行状态</li><li><strong>重启</strong>：重启运行中的容器</li><li><strong>删除</strong>：移除不需要的容器</li><li><strong>日志</strong>：实时查看容器日志输出</li></ul><h3 id="容器详情" tabindex="-1">容器详情 <a class="header-anchor" href="#容器详情" aria-label="Permalink to &quot;容器详情&quot;">​</a></h3><p>查看容器的详细信息：</p><ul><li>运行状态和资源占用</li><li>端口映射</li><li>挂载卷</li><li>环境变量</li><li>网络配置</li></ul><h2 id="镜像管理" tabindex="-1">镜像管理 <a class="header-anchor" href="#镜像管理" aria-label="Permalink to &quot;镜像管理&quot;">​</a></h2><ul><li>查看本地镜像列表</li><li>拉取 Docker Hub 镜像</li><li>删除不需要的镜像</li><li>查看镜像层信息</li></ul><div class="tip custom-block"><p class="custom-block-title">Docker 镜像加速</p><p>国内用户拉取 Docker Hub 镜像可能很慢，RDE 会员可使用内置的 <a href="/zh/docs/guide/mirror.html">Docker 镜像加速</a> 服务。</p></div><h2 id="docker-compose-支持" tabindex="-1">docker-compose 支持 <a class="header-anchor" href="#docker-compose-支持" aria-label="Permalink to &quot;docker-compose 支持&quot;">​</a></h2><p>支持通过 docker-compose.yml 文件批量管理应用：</p><ul><li>上传或粘贴 docker-compose.yml</li><li>一键 <code>up</code> / <code>down</code></li><li>查看 compose 项目状态</li></ul>',17)])])}const k=o(r,[["render",t]]);export{p as __pageData,k as default};
